<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>Falling Sand Simulator</title>
  <style>
    * {
      margin: 0;
      padding: 0;
      box-sizing: border-box;
    }

    body {
      background-color: #1e1e1e;
      color: #e0e0e0;
      font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Arial, sans-serif;
      display: flex;
      flex-direction: column;
      align-items: center;
      justify-content: center;
      min-height: 100vh;
      padding: 20px;
      gap: 20px;
    }

    h1 {
      color: #ffffff;
      font-size: 28px;
    }

    #canvas-container {
      border: 2px solid #444;
      background-color: #0a0a0a;
      border-radius: 4px;
      overflow: hidden;
    }

    canvas {
      display: block;
      image-rendering: pixelated;
    }

    .controls {
      display: flex;
      gap: 10px;
      flex-wrap: wrap;
      justify-content: center;
      max-width: 700px;
    }

    button {
      padding: 10px 16px;
      border: none;
      border-radius: 4px;
      font-size: 13px;
      font-weight: 500;
      cursor: pointer;
      transition: all 0.15s ease;
      background-color: #424242;
      color: #ffffff;
      user-select: none;
    }

    button:hover {
      background-color: #545454;
    }

    button:active {
      transform: scale(0.96);
    }

    button.selected {
      background-color: #bb86fc;
      color: #ffffff;
      box-shadow: 0 0 8px rgba(187, 134, 252, 0.3);
    }

    #clear {
      background-color: #d32f2f;
      margin-left: auto;
    }

    #clear:hover {
      background-color: #f44336;
    }
  </style>
</head>
<body>
  <h1>Falling Sand</h1>

  <div id="canvas-container">
    <canvas id="sand"></canvas>
  </div>

  <div class="controls">
    <button id="mat-sand">🟫 Sand</button>
    <button id="mat-water">💧 Water</button>
    <button id="mat-wall">⬛ Wall</button>
    <button id="mat-acid">☣️ Acid</button>
    <button id="mat-empty">✋ Eraser</button>
    <button id="clear">Clear All</button>
  </div>

  <script>
    const MATERIALS = {
      EMPTY: 0,
      SAND: 1,
      WATER: 2,
      WALL: 3,
      ACID: 4
    };

    const MATERIAL_NAMES = {
      0: 'empty',
      1: 'sand',
      2: 'water',
      3: 'wall',
      4: 'acid'
    };

    const MATERIAL_COLORS = {
      0: '#1a1a1a',
      1: '#d4a574',
      2: '#4a90e2',
      3: '#2a2a2a',
      4: '#ff5252'
    };

    const GRID_WIDTH = 100;
    const GRID_HEIGHT = 100;
    const CELL_SIZE = 5;

    const canvas = document.getElementById('sand');
    const ctx = canvas.getContext('2d');

    canvas.width = GRID_WIDTH * CELL_SIZE;
    canvas.height = GRID_HEIGHT * CELL_SIZE;

    let grid = Array(GRID_HEIGHT).fill(null).map(() => Array(GRID_WIDTH).fill(MATERIALS.EMPTY));
    let selectedMaterial = MATERIALS.SAND;
    let isMouseDown = false;
    let lastX = -1;
    let lastY = -1;

    document.getElementById('mat-sand').addEventListener('click', () => {
      selectedMaterial = MATERIALS.SAND;
      updateButtonStates();
    });

    document.getElementById('mat-water').addEventListener('click', () => {
      selectedMaterial = MATERIALS.WATER;
      updateButtonStates();
    });

    document.getElementById('mat-wall').addEventListener('click', () => {
      selectedMaterial = MATERIALS.WALL;
      updateButtonStates();
    });

    document.getElementById('mat-acid').addEventListener('click', () => {
      selectedMaterial = MATERIALS.ACID;
      updateButtonStates();
    });

    document.getElementById('mat-empty').addEventListener('click', () => {
      selectedMaterial = MATERIALS.EMPTY;
      updateButtonStates();
    });

    document.getElementById('clear').addEventListener('click', () => {
      grid = Array(GRID_HEIGHT).fill(null).map(() => Array(GRID_WIDTH).fill(MATERIALS.EMPTY));
    });

    function updateButtonStates() {
      const buttons = [
        { id: 'mat-sand', mat: MATERIALS.SAND },
        { id: 'mat-water', mat: MATERIALS.WATER },
        { id: 'mat-wall', mat: MATERIALS.WALL },
        { id: 'mat-acid', mat: MATERIALS.ACID },
        { id: 'mat-empty', mat: MATERIALS.EMPTY }
      ];

      buttons.forEach(btn => {
        const elem = document.getElementById(btn.id);
        if (btn.mat === selectedMaterial) {
          elem.classList.add('selected');
        } else {
          elem.classList.remove('selected');
        }
      });
    }

    canvas.addEventListener('mousedown', (e) => {
      isMouseDown = true;
      const rect = canvas.getBoundingClientRect();
      const x = Math.floor((e.clientX - rect.left) / CELL_SIZE);
      const y = Math.floor((e.clientY - rect.top) / CELL_SIZE);
      paintCell(x, y);
      lastX = x;
      lastY = y;
    });

    canvas.addEventListener('mousemove', (e) => {
      if (!isMouseDown) return;

      const rect = canvas.getBoundingClientRect();
      const x = Math.floor((e.clientX - rect.left) / CELL_SIZE);
      const y = Math.floor((e.clientY - rect.top) / CELL_SIZE);

      if (lastX !== -1 && lastY !== -1) {
        bresenhamLine(lastX, lastY, x, y);
      }

      paintCell(x, y);
      lastX = x;
      lastY = y;
    });

    canvas.addEventListener('mouseup', () => {
      isMouseDown = false;
      lastX = -1;
      lastY = -1;
    });

    canvas.addEventListener('mouseleave', () => {
      isMouseDown = false;
      lastX = -1;
      lastY = -1;
    });

    function paintCell(x, y) {
      if (x < 0 || x >= GRID_WIDTH || y < 0 || y >= GRID_HEIGHT) return;
      grid[y][x] = selectedMaterial;
    }

    function bresenhamLine(x0, y0, x1, y1) {
      const dx = Math.abs(x1 - x0);
      const dy = Math.abs(y1 - y0);
      const sx = x0 < x1 ? 1 : -1;
      const sy = y0 < y1 ? 1 : -1;
      let err = dx - dy;

      let x = x0;
      let y = y0;

      while (true) {
        paintCell(x, y);

        if (x === x1 && y === y1) break;

        const e2 = 2 * err;
        if (e2 > -dy) {
          err -= dy;
          x += sx;
        }
        if (e2 < dx) {
          err += dx;
          y += sy;
        }
      }
    }

    function tick() {
      let nextGrid = grid.map(row => [...row]);

      for (let y = GRID_HEIGHT - 1; y >= 0; y--) {
        for (let x = 0; x < GRID_WIDTH; x++) {
          let material = grid[y][x];

          if (material === MATERIALS.SAND) {
            if (nextGrid[y][x] !== MATERIALS.SAND) continue;

            if (y + 1 < GRID_HEIGHT) {
              let below = nextGrid[y + 1][x];
              if (below === MATERIALS.EMPTY) {
                nextGrid[y + 1][x] = MATERIALS.SAND;
                nextGrid[y][x] = MATERIALS.EMPTY;
                continue;
              } else if (below === MATERIALS.WATER || below === MATERIALS.ACID) {
                nextGrid[y + 1][x] = MATERIALS.SAND;
                nextGrid[y][x] = below;
                continue;
              }
            }

            const dirs = Math.random() > 0.5 
              ? [[x - 1, y + 1], [x + 1, y + 1]]
              : [[x + 1, y + 1], [x - 1, y + 1]];

            for (let [nx, ny] of dirs) {
              if (nx >= 0 && nx < GRID_WIDTH && ny < GRID_HEIGHT && nextGrid[ny][nx] === MATERIALS.EMPTY) {
                nextGrid[ny][nx] = MATERIALS.SAND;
                nextGrid[y][x] = MATERIALS.EMPTY;
                break;
              }
            }
          } else if (material === MATERIALS.WATER) {
            if (nextGrid[y][x] !== MATERIALS.WATER) continue;

            if (y + 1 < GRID_HEIGHT) {
              let below = nextGrid[y + 1][x];
              if (below === MATERIALS.EMPTY) {
                nextGrid[y + 1][x] = MATERIALS.WATER;
                nextGrid[y][x] = MATERIALS.EMPTY;
                continue;
              }
            }

            const dirs = Math.random() > 0.5 
              ? [[x - 1, y], [x + 1, y]]
              : [[x + 1, y], [x - 1, y]];

            for (let [nx, ny] of dirs) {
              if (nx >= 0 && nx < GRID_WIDTH && nextGrid[ny][nx] === MATERIALS.EMPTY) {
                nextGrid[ny][nx] = MATERIALS.WATER;
                nextGrid[y][x] = MATERIALS.EMPTY;
                break;
              }
            }
          } else if (material === MATERIALS.ACID) {
            if (nextGrid[y][x] !== MATERIALS.ACID) continue;

            if (y + 1 < GRID_HEIGHT) {
              let below = nextGrid[y + 1][x];
              if (below === MATERIALS.EMPTY) {
                nextGrid[y + 1][x] = MATERIALS.ACID;
                nextGrid[y][x] = MATERIALS.EMPTY;
                continue;
              } else if (below === MATERIALS.SAND || below === MATERIALS.WALL) {
                nextGrid[y + 1][x] = MATERIALS.ACID;
                nextGrid[y][x] = MATERIALS.EMPTY;
                continue;
              }
            }

            const dirs = Math.random() > 0.5 
              ? [[x - 1, y], [x + 1, y]]
              : [[x + 1, y], [x - 1, y]];

            for (let [nx, ny] of dirs) {
              if (nx >= 0 && nx < GRID_WIDTH) {
                let cell = nextGrid[ny][nx];
                if (cell === MATERIALS.EMPTY) {
                  nextGrid[ny][nx] = MATERIALS.ACID;
                  nextGrid[y][x] = MATERIALS.EMPTY;
                  break;
                } else if (cell === MATERIALS.SAND || cell === MATERIALS.WALL) {
                  nextGrid[ny][nx] = MATERIALS.ACID;
                  nextGrid[y][x] = MATERIALS.EMPTY;
                  break;
                }
              }
            }
          }
        }
      }

      grid = nextGrid;
    }

    function draw() {
      ctx.fillStyle = MATERIAL_COLORS[MATERIALS.EMPTY];
      ctx.fillRect(0, 0, canvas.width, canvas.height);

      for (let y = 0; y < GRID_HEIGHT; y++) {
        for (let x = 0; x < GRID_WIDTH; x++) {
          const material = grid[y][x];
          ctx.fillStyle = MATERIAL_COLORS[material];
          ctx.fillRect(x * CELL_SIZE, y * CELL_SIZE, CELL_SIZE, CELL_SIZE);
        }
      }
    }

    function animate() {
      tick();
      draw();
      requestAnimationFrame(animate);
    }

    updateButtonStates();
    draw();
    animate();

    window.sim = {
      w: GRID_WIDTH,
      h: GRID_HEIGHT,
      tick(n) {
        for (let i = 0; i < n; i++) {
          tick();
        }
      },
      get(x, y) {
        if (x < 0 || x >= GRID_WIDTH || y < 0 || y >= GRID_HEIGHT) return 'empty';
        return MATERIAL_NAMES[grid[y][x]];
      },
      set(x, y, material) {
        if (x < 0 || x >= GRID_WIDTH || y < 0 || y >= GRID_HEIGHT) return;
        const codes = { empty: 0, sand: 1, water: 2, wall: 3, acid: 4 };
        grid[y][x] = codes[material] ?? 0;
      },
      clear() {
        grid = Array(GRID_HEIGHT).fill(null).map(() => Array(GRID_WIDTH).fill(MATERIALS.EMPTY));
      }
    };
  </script>
</body>
</html>
